script.code:
// Hard gates for the headless SO -> GD (Created) conversion.
//
// picking_setup is read ORG-scoped on purpose: that is the exact row GDheadWorkflow's
// "Resolve Picking Setup" reads to decide picking_mode, so gating on any other row would
// gate on config that does not actually drive allocation.
const one = (raw) => (Array.isArray(raw) ? raw[0] : raw);

const soRaw = {{node:search_so.data.data}} || [];
const soList = Array.isArray(soRaw) ? soRaw : [soRaw];
const setup = one({{node:get_picking_setup.data.data}});
const rule = one({{node:get_gd_rule.data.data}});
const acc = one({{node:get_acc_int.data.data}});

let blocked = 0;
let message = "";

if (!soList.length || !soList[0]) {
  blocked = 1;
  message = "No Sales Order was found for the current selection.";
} else if (!setup) {
  blocked = 1;
  message = "Cannot convert to Goods Delivery. Please check your picking setup.";
} else if (
  Number(setup.picking_required) === 1 &&
  setup.picking_after === "Sales Order"
) {
  // SO -> Picking Plan -> GD orgs: the GD must come from a Picking Plan, not the SO.
  blocked = 1;
  message =
    "Cannot convert to Goods Delivery after Sales Order. Please check your picking setup.";
} else if (Number(setup.convert_gd_created) !== 1) {
  // Backstop: the caller already reads this flag to pick the conversion path, so reaching
  // here means the setup changed under it (or the workflow was called directly).
  blocked = 1;
  message =
    "Direct conversion to a Created Goods Delivery is turned off. Enable <b>Auto Create as Created</b> in your picking setup.";
} else if ((setup.picking_mode || "Manual") !== "Auto") {
  // Without Auto picking mode the save workflow never allocates stock, so the GD would be
  // saved as Created with no reserved inventory at all.
  blocked = 1;
  message =
    "<b>Auto Create as Created</b> requires Picking Mode to be <b>Auto</b>, otherwise stock cannot be allocated automatically. Please fix your picking setup.";
}

const materialIds = [];
const customerIds = [];

if (blocked === 0) {
  for (const so of soList) {
    const custId = Array.isArray(so.customer_name)
      ? so.customer_name[0]
      : so.customer_name;
    if (custId && customerIds.indexOf(String(custId)) === -1) {
      customerIds.push(String(custId));
    }
    for (const line of so.table_so || []) {
      // On a SO line, item_name holds the material FK and item_id the display code.
      const materialId = line.item_name;
      if (materialId && materialIds.indexOf(String(materialId)) === -1) {
        materialIds.push(String(materialId));
      }
    }
  }
}

// The "in" filters downstream need a non-empty list.
if (materialIds.length === 0) materialIds.push("0");
if (customerIds.length === 0) customerIds.push("0");

return {
  blocked: blocked,
  message: message,
  materialIds: materialIds,
  customerIds: customerIds,
  deliveryNoType: rule ? rule.id : -9999,
  accIntegrationType: acc ? acc.acc_integration_type : "",
};

// Builds the allData payload(s) that the GD form would have produced, so GDheadWorkflow
// can be called headlessly with saveAs = "Created".
//
// This is the server-side port of GD_funcProcessGDLineItem (picking_mode = "Auto" branch
// only -- Manual is blocked upstream) + GDonChangeSO + GDonChangeCustomer + the non-UI half
// of GDonMounted.
//
// No stock lookup here on purpose: GDheadWorkflow allocates with enforceStockCheck = 1 and
// runs its pre-flight inventory check BEFORE the insert, so a shortfall already returns 400
// with nothing written. Re-checking balances here would be a redundant fetch AND a stale
// snapshot (each GD in the loop consumes stock the next one can no longer see).

const gdType = {{workflowparams:gd_type}};
const plantId = {{workflowparams:plant_id}};
const organizationId = {{workflowparams:organization_id}};
const createdBy = {{workflowparams:created_by}};
const deliveryNoType = {{node:code_gate.data.deliveryNoType}};
const accIntegrationType = {{node:code_gate.data.accIntegrationType}};

const soRaw = {{node:search_so.data.data}} || [];
const soList = Array.isArray(soRaw) ? soRaw : [soRaw];
const itemRaw = {{node:search_items.data.data}} || [];
const itemList = Array.isArray(itemRaw) ? itemRaw : [itemRaw];
const custRaw = {{node:search_customers.data.data}} || [];
const custList = Array.isArray(custRaw) ? custRaw : [custRaw];

const itemMap = {};
for (const it of itemList) {
  if (it && it.id) itemMap[String(it.id)] = it;
}
const custMap = {};
for (const c of custList) {
  if (c && c.id) custMap[String(c.id)] = c;
}

const roundQty = (value) => Math.round((parseFloat(value) || 0) * 1000) / 1000;
const scalar = (v) => (Array.isArray(v) ? v[0] : v);

// How many base UOM units make up 1 unit of the given UOM (1 for the base UOM).
const getBaseQty = (itemData, uom) => {
  if (!itemData || !uom || uom === itemData.based_uom) return 1;
  const conv = (itemData.table_uom_conversion || []).find(
    (c) => c.alt_uom_id === uom
  );
  return conv && conv.base_qty ? conv.base_qty : 1;
};

const convertToBaseUOM = (quantity, uom, itemData) =>
  (parseFloat(quantity) || 0) * getBaseQty(itemData, uom);

// GDonChangeSO: only the fields belonging to the SO's delivery method are carried over.
// (The old mapHeaderData in SOconvertGDworkflow assigned driver_name / ic_no / shipping_date /
// freight_charges / est_arrival_date / tracking_number twice in one object literal, so the
// Company-Truck and Shipping-Service values always overwrote the Self-Pickup and Courier ones.)
const applyDeliveryMethod = (header, so) => {
  header.gd_delivery_method = so.so_delivery_method || "";

  switch (so.so_delivery_method) {
    case "Self Pickup":
      header.driver_name = so.cp_driver_name;
      header.ic_no = so.cp_ic_no;
      header.driver_contact_no = so.cp_driver_contact_no;
      header.sp_vehicle_no = so.cp_vehicle_number;
      header.vehicle_no = so.cp_vehicle_number;
      header.pickup_date = so.cp_pickup_date;
      header.validity_of_collection = so.validity_of_collection;
      break;

    case "Courier Service":
      header.courier_company = so.cs_courier_company;
      header.shipping_date = so.cs_shipping_date;
      header.tracking_number = so.cs_tracking_number;
      header.est_arrival_date = so.est_arrival_date;
      header.freight_charges = so.cs_freight_charges;
      break;

    case "Company Truck":
      header.driver_name = so.ct_driver_name;
      header.driver_contact_no = so.ct_driver_contact_no;
      header.ic_no = so.ct_ic_no;
      header.sp_vehicle_no = so.ct_vehicle_number;
      header.vehicle_no = so.ct_vehicle_number;
      header.est_delivery_date = so.ct_est_delivery_date;
      // GDheadWorkflow's add-node writes the delivery_cost column from allData.driver_cost,
      // while the form field is delivery_cost -- set both so neither path loses the value.
      header.delivery_cost = so.ct_delivery_cost;
      header.driver_cost = so.ct_delivery_cost;
      break;

    case "Shipping Service":
      header.shipping_company = so.ss_shipping_company;
      // ss_shippping_date (three p's) really is the SO column name.
      header.shipping_date = so.ss_shippping_date;
      header.freight_charges = so.ss_freight_charges;
      header.shipping_method = so.ss_shipping_method;
      header.est_arrival_date = so.ss_est_arrival_date;
      header.tracking_number = so.ss_tracking_number;
      break;

    case "3rd Party Transporter":
      header.tpt_vehicle_number = so.tpt_vehicle_number;
      header.tpt_transport_name = so.tpt_transport_name;
      header.tpt_ic_no = so.tpt_ic_no;
      header.tpt_driver_contact_no = so.tpt_driver_contact_no;
      header.tpt_driver_name = so.tpt_driver_name;
      break;
  }
};

// One GD line per deliverable SO line. Returns null for lines with nothing left to ship.
const buildLine = (line, so) => {
  const orderedQty = parseFloat(line.so_quantity || 0);
  const deliveredQty = parseFloat(line.delivered_qty || 0);
  const plannedQty = parseFloat(line.planned_qty || 0);

  // Fully delivered lines never make it onto the GD (GD_funcProcessGDLineItem filters them out).
  if (deliveredQty === orderedQty) return null;

  const undeliveredQty = roundQty(orderedQty - deliveredQty);
  // Quantity already covered by a Picking Plan / another GD is not ours to deliver.
  const suggestedQty = roundQty(Math.max(0, undeliveredQty - plannedQty));
  if (suggestedQty <= 0) return null;

  const materialId = line.item_name ? String(line.item_name) : "";
  const itemData = materialId ? itemMap[materialId] : null;
  const altUOM = line.so_item_uom ? String(line.so_item_uom) : "";

  const isSerialized = !!(itemData && itemData.serial_number_management === 1);
  // A stock_control=0 / show_delivery=0 item carries no stock: treat it like a description row.
  const isNonStock = !!(
    itemData &&
    itemData.stock_control === 0 &&
    itemData.show_delivery === 0
  );

  const row = {
    material_id: materialId,
    material_name: line.item_id || "",
    gd_material_desc: line.so_desc || "",
    more_desc: line.more_desc || "",
    line_remark_1: line.line_remark_1 || "",
    line_remark_2: line.line_remark_2 || "",
    line_remark_3: line.line_remark_3 || "",
    custom_fields: line.custom_fields || {},
    tariff_id: line.tariff_id,
    item_category_id: line.item_category_id
      ? String(line.item_category_id)
      : "",
    unit_price: parseFloat(line.so_item_price || 0),
    total_price: parseFloat(line.so_amount || 0),
    line_so_no: so.so_no,
    line_so_id: String(so.id),
    so_line_item_id: String(line.id),
    is_internal: !!(so.source_po_id || line.source_po_line_item_id),
    base_uom_id: itemData ? itemData.based_uom || "" : "",
    item_costing_method: itemData ? itemData.material_costing_method : "",
  };

  if (isSerialized) {
    // Serialized items are handled entirely in base UOM.
    const finalQtyBase = roundQty(convertToBaseUOM(suggestedQty, altUOM, itemData));
    row.gd_order_quantity = roundQty(convertToBaseUOM(orderedQty, altUOM, itemData));
    row.gd_delivered_qty = roundQty(convertToBaseUOM(deliveredQty, altUOM, itemData));
    row.gd_initial_delivered_qty = row.gd_delivered_qty;
    row.gd_undelivered_qty = roundQty(convertToBaseUOM(undeliveredQty, altUOM, itemData));
    row.gd_order_uom_id = itemData.based_uom;
    row.good_delivery_uom_id = itemData.based_uom;
    row.gd_qty = finalQtyBase;
    row.base_qty = finalQtyBase;
  } else {
    row.gd_order_quantity = orderedQty;
    row.gd_delivered_qty = isNonStock
      ? roundQty(deliveredQty + undeliveredQty)
      : deliveredQty;
    row.gd_initial_delivered_qty = deliveredQty;
    row.gd_undelivered_qty = isNonStock ? 0 : undeliveredQty;
    row.gd_order_uom_id = altUOM;
    row.good_delivery_uom_id = altUOM;
    row.gd_qty = suggestedQty;
    row.base_qty = itemData
      ? roundQty(convertToBaseUOM(suggestedQty, altUOM, itemData))
      : suggestedQty;
  }

  // Packing + net weight, seeded from the row's final delivery qty/uom (mirrors
  // GD_funcProcessGDLineItem step 3.5). weight_conversion comes from the SO line when the
  // user set one there; otherwise it is derived from the item's net weight.
  const uom = row.good_delivery_uom_id;
  const qty = parseFloat(row.gd_qty) || 0;
  const packingDetail =
    ((itemData && itemData.table_packing_detail) || []).find(
      (p) => p.uom_id === uom
    ) || null;
  const packingConversion = (packingDetail && packingDetail.quantity) || 1;
  // The SO line's weight_conversion is a per-unit weight expressed in the SO's UOM, so it can
  // only be reused when the GD row kept that UOM. Serialized rows were switched to the base
  // UOM above, so their weight has to be derived from the item instead.
  const soWeightConversion = uom === altUOM ? line.weight_conversion : null;
  const weightConversion =
    soWeightConversion !== undefined &&
    soWeightConversion !== null &&
    soWeightConversion !== ""
      ? Number(soWeightConversion)
      : roundQty((Number(itemData && itemData.net_weight) || 0) * getBaseQty(itemData, uom));

  row.packing_uom = (packingDetail && packingDetail.packing_uom_id) || "";
  row.packing_conversion = packingConversion;
  row.packing_qty = packingConversion ? roundQty(qty / packingConversion) : 0;
  row.weight_conversion = weightConversion;
  row.net_weight = roundQty(qty * weightConversion);

  return row;
};

// gd_total prorates each SO line's amount by the quantity actually being delivered,
// the same way GDconfirmDialog recalculates it in the form. The credit-limit check is fed
// from this value.
const calcGdTotal = (lines) => {
  let total = 0;
  for (const row of lines) {
    const orderQty = parseFloat(row.gd_order_quantity) || 0;
    const gdQty = parseFloat(row.gd_qty) || 0;
    const totalPrice = parseFloat(row.total_price) || 0;
    if (orderQty > 0 && gdQty > 0) {
      total += (totalPrice / orderQty) * gdQty;
    }
  }
  return roundQty(total);
};

const buildHeader = (sos, lines) => {
  const primary = sos[0];
  const customerId = scalar(primary.customer_name);
  const customer = customerId ? custMap[String(customerId)] : null;
  const contact =
    customer && customer.contact_list && customer.contact_list.length > 0
      ? customer.contact_list[0]
      : null;

  const header = {
    // The record becomes Created through the saveAs param (GDheadWorkflow's add-node writes
    // gd_status from it). allData.gd_status stays "Draft" -- exactly what an unsaved form
    // carries -- because the allocator reads it: gd_status "Created" would set
    // includeReservedQty = 1 and let this GD consume stock reserved for other documents.
    gd_status: "Draft",
    page_status: "Add",
    plant_id: plantId,
    organization_id: organizationId,
    is_select_picking: 0,

    so_id: sos.map((s) => String(s.id)),
    so_no: sos.map((s) => s.so_no).join(", "),

    // Left empty on purpose: GDheadWorkflow substitutes its "issued" placeholder and the
    // platform's number rule stamps the real delivery_no on insert.
    delivery_no: "",
    delivery_no_type: deliveryNoType,
    delivery_date: new Date().toISOString().replace("T", " "),
    gd_created_by: createdBy,
    acc_integration_type: accIntegrationType,

    customer_name: customerId,
    // so_currency is already the currency CODE (the SO copies it off the customer), so there
    // is no customer -> currency hop to make here.
    currency_code: scalar(primary.so_currency) || "",

    gd_contact_name: contact ? contact.person_name : "",
    contact_number: contact ? contact.mobile_number : "",
    email_address: contact ? contact.person_email : "",

    last_sync_date: customer ? customer.last_sync_date : null,
    customer_credit_limit: customer ? customer.customer_credit_limit : null,
    overdue_limit: customer ? customer.overdue_limit : null,
    outstanding_balance: customer ? customer.outstanding_balance : null,
    overdue_inv_total_amount: customer
      ? customer.overdue_inv_total_amount
      : null,
    is_accurate: customer ? customer.is_accurate : null,

    gd_billing_address: primary.cust_billing_address || "",
    gd_shipping_address: primary.cust_shipping_address || "",

    billing_address_line_1: primary.billing_address_line_1 || "",
    billing_address_line_2: primary.billing_address_line_2 || "",
    billing_address_line_3: primary.billing_address_line_3 || "",
    billing_address_line_4: primary.billing_address_line_4 || "",
    billing_address_city: primary.billing_address_city || "",
    billing_postal_code: primary.billing_postal_code || "",
    billing_address_state: primary.billing_address_state || "",
    billing_address_country: primary.billing_address_country || "",
    billing_address_name: primary.billing_address_name || "",
    billing_address_phone: primary.billing_address_phone || "",
    billing_attention: primary.billing_attention || "",
    billing_address_fax: primary.billing_address_fax || "",
    billing_address_code: primary.billing_address_code || "",

    shipping_address_line_1: primary.shipping_address_line_1 || "",
    shipping_address_line_2: primary.shipping_address_line_2 || "",
    shipping_address_line_3: primary.shipping_address_line_3 || "",
    shipping_address_line_4: primary.shipping_address_line_4 || "",
    shipping_address_city: primary.shipping_address_city || "",
    shipping_postal_code: primary.shipping_postal_code || "",
    shipping_address_state: primary.shipping_address_state || "",
    shipping_address_country: primary.shipping_address_country || "",
    shipping_address_name: primary.shipping_address_name || "",
    shipping_address_phone: primary.shipping_address_phone || "",
    shipping_attention: primary.shipping_attention || "",
    shipping_address_fax: primary.shipping_address_fax || "",
    shipping_address_code: primary.shipping_address_code || "",

    gd_area_id: primary.so_area_id || "",
    sales_person: primary.so_sales_person ? [primary.so_sales_person] : [],
    order_tnc: primary.so_tnc || "",
    order_payment_details: primary.so_payment_details || "",
    order_delivery_term: primary.so_delivery_term || "",
    order_remark: primary.so_remarks || "",
    order_remark2: primary.so_remarks2 || "",
    order_remark3: primary.so_remarks3 || "",
    order_remark4: primary.so_remarks4 || "",
    order_remark5: primary.so_remarks5 || "",

    table_gd: lines,
    gd_total: calcGdTotal(lines),
  };

  applyDeliveryMethod(header, primary);

  return header;
};

const payloads = [];
const blocked = [];

const makePayload = (sos) => {
  const lines = [];
  for (const so of sos) {
    for (const line of so.table_so || []) {
      const row = buildLine(line, so);
      if (row) lines.push(row);
    }
  }

  const soNo = sos.map((s) => s.so_no).join(", ");

  if (lines.length === 0) {
    blocked.push({
      so_no: soNo,
      reason:
        "Nothing left to deliver - every line is already delivered or covered by another delivery.",
    });
    return;
  }

  payloads.push({ so_no: soNo, allData: buildHeader(sos, lines) });
};

if (gdType === "single") {
  makePayload(soList);
} else {
  for (const so of soList) {
    makePayload([so]);
  }
}

return {
  payloads: payloads,
  blocked: blocked,
  hasPayloads: payloads.length > 0 ? 1 : 0,
  blockedMessage: blocked.map((b) => b.so_no + ": " + b.reason).join("<br>"),
};

// Per-run redis namespace, so concurrent conversions never share an accumulator.
const createdBy = {{workflowparams:created_by}} || "";

return {
  unique: createdBy + "_" + Date.now(),
};

// Accumulate one entry per GD attempt. GDheadWorkflow returns 200 on success and
// 400 / 401 / 402 / 403 on failure -- and every one of those failure paths returns
// BEFORE its add-node, so a non-200 code means nothing was written for this SO.
const raw = {{node:get_results.data}};

let results = [];
if (raw) {
  results = typeof raw === "string" ? JSON.parse(raw) : raw;
}
if (!Array.isArray(results)) results = [];

const gdCode = {{node:wf_gd_head.data.code}};
const gdMessage = {{node:wf_gd_head.data.message}};
const gdId = {{node:wf_gd_head.data.gdId}};
const soNo = {{node:loop_payloads.so_no}};

results.push({
  so_no: soNo || "",
  code: gdCode ? String(gdCode) : "",
  message: gdMessage || "",
  gd_id: gdId ? String(gdId) : "",
});

return { results: results };

const raw = {{node:get_results_final.data}};

let results = [];
if (raw) {
  results = typeof raw === "string" ? JSON.parse(raw) : raw;
}
if (!Array.isArray(results)) results = [];

const gdIds = results
  .filter((r) => r && r.gd_id && r.code === "200")
  .map((r) => String(r.gd_id));

// The "in" filter downstream needs a non-empty list.
if (gdIds.length === 0) gdIds.push("0");

return { gdIds: gdIds };

// The real delivery_no is only known after the insert (the platform's number rule stamps
// it), so it is read back here rather than guessed.
const raw = {{node:get_results_final.data}};

let results = [];
if (raw) {
  results = typeof raw === "string" ? JSON.parse(raw) : raw;
}
if (!Array.isArray(results)) results = [];

const gdRaw = {{node:search_gds.data.data}} || [];
const gdList = Array.isArray(gdRaw) ? gdRaw : [gdRaw];

const deliveryNoById = {};
for (const gd of gdList) {
  if (gd && gd.id) deliveryNoById[String(gd.id)] = gd.delivery_no || "";
}

const created = [];
const blocked = [];

for (const r of results) {
  if (r.code === "200" && r.gd_id) {
    created.push({
      so_no: r.so_no,
      delivery_no: deliveryNoById[r.gd_id] || "",
    });
  } else {
    blocked.push({
      so_no: r.so_no,
      reason: r.message || "Failed to create the Goods Delivery.",
    });
  }
}

// SOs dropped before we ever called GDheadWorkflow (nothing left to deliver).
const preBlocked = {{node:code_build.data.blocked}} || [];
for (const b of preBlocked) {
  blocked.push(b);
}

return {
  code: "200",
  message:
    "Created " +
    created.length +
    " goods deliver" +
    (created.length === 1 ? "y" : "ies") +
    (blocked.length > 0 ? ", " + blocked.length + " not converted." : "."),
  created: created,
  blocked: blocked,
  createdCount: created.length,
  blockedCount: blocked.length,
};
